// Extract topics array from HTTP response
const items = $input.all();
const topics = items.map(i => i.json).filter(t => t.topic);
if (topics.length === 0) {
  return [{ json: { topics: [] } }];
}
return [{ json: { topics: topics.map(t => t.topic) } }];

// Build HTML email body from bulk-fetch results
const results = $input.all().map(i => i.json);
const date = new Date().toLocaleDateString('en-US', { weekday:'long', year:'numeric', month:'long', day:'numeric' });

let totalPapers = 0;
let sections = '';

for (const r of results) {
  if (!r.count || r.count === 0) continue;
  totalPapers += r.count;
  const papers = (r.papers || []).slice(0, 5);
  let rows = '';
  for (const p of papers) {
    const authors = Array.isArray(p.authors) ? p.authors.slice(0,2).join(', ') : '';
    const summary = p.summary ? `<p style="color:#c0d4ff;font-size:13px;border-left:3px solid #6C63FF;padding-left:10px;">${p.summary.substring(0,200)}...</p>` : '';
    rows += `<div style="border-bottom:1px solid #2a2d3e;padding:14px 0;"><a href="${p.url}" style="color:#6C63FF;font-weight:600;">${p.title}</a><br><small style="color:#aaa;">${authors}</small>${summary}</div>`;
  }
  sections += `<div style="background:#1A1D27;border-radius:12px;padding:20px;margin-bottom:16px;"><h3 style="color:#6C63FF;margin:0 0 12px;">Topic: ${r.topic} (${r.count} new)</h3>${rows}</div>`;
}

if (totalPapers === 0) {
  return [{ json: { skip: true, total: 0 } }];
}

const html = `<html><body style="background:#0E1117;color:#FAFAFA;font-family:sans-serif;padding:24px;"><div style="max-width:700px;margin:auto;"><div style="background:linear-gradient(135deg,#6C63FF,#4a42cc);padding:28px;border-radius:16px;margin-bottom:20px;"><h1 style="margin:0;">🔬 AutoResearch AI</h1><h2 style="margin:8px 0 0;opacity:.85;">Daily Paper Alert</h2><p style="opacity:.7;margin:8px 0 0;">${date}</p></div>${sections}<p style="color:#888;font-size:12px;text-align:center;">Sent by AutoResearch AI · <a href="http://localhost:8501" style="color:#6C63FF;">Open Dashboard</a></p></div></body></html>`;

return [{ json: { html, total: totalPapers, skip: false, date } }];
